-- Cambios: campos padre/madre/legajo/clave_fiscal_arca, ARCA en vez de AFIP,
-- código actividad 682010, planilla consorcios, bloque costos_info, periodos 2024-2025.

UPDATE public.formularios SET schema = '{"sections": [{"title": "Datos personales", "fields": [{"name": "apellido", "type": "text", "label": "Apellido", "required": true}, {"name": "nombre", "type": "text", "label": "Nombre", "required": true}, {"name": "dni", "type": "text", "label": "DNI", "required": true, "hint": "Sin puntos ni guiones."}, {"name": "padre_apellido_nombre", "type": "text", "label": "Apellido y nombres del padre", "required": true}, {"name": "madre_apellido_nombre", "type": "text", "label": "Apellido y nombres de la madre", "required": true}, {"name": "cuit", "type": "text", "label": "CUIT/CUIL", "required": true, "hint": "11 d\u00edgitos sin guiones."}, {"name": "clave_fiscal_arca", "type": "text", "label": "Clave Fiscal ARCA", "required": true, "hint": "Tu clave fiscal de ARCA (ex AFIP). La usamos solo para gestionar este tr\u00e1mite y futuros tuyos."}, {"name": "email", "type": "email", "label": "Correo electr\u00f3nico", "required": true, "placeholder": "tu@correo.com"}, {"name": "celular", "type": "tel", "label": "Celular", "required": true, "hint": "Inclu\u00ed caracter\u00edstica con el 9 (m\u00f3vil).", "placeholder": "+54 11 5555-1234"}, {"name": "fecha_nacimiento", "type": "date", "label": "Fecha de nacimiento", "required": true}, {"name": "nacionalidad", "type": "text", "label": "Nacionalidad", "required": true, "placeholder": "Argentina"}, {"name": "estado_civil", "type": "select", "label": "Estado civil", "options": ["soltero", "casado", "divorciado", "viudo", "union_convivencial"], "required": true, "hint": "Si seleccion\u00e1s casado/a o uni\u00f3n convivencial complet\u00e1 los datos del c\u00f3nyuge debajo."}, {"name": "apellido_nombre_conyuge", "type": "text", "label": "Apellido y nombre del c\u00f3nyuge", "required": true, "condition": {"field": "estado_civil", "equals": ["casado", "union_convivencial"]}}, {"name": "cuit_conyuge", "type": "text", "label": "CUIT/CUIL del c\u00f3nyuge", "required": true, "condition": {"field": "estado_civil", "equals": ["casado", "union_convivencial"]}}]}, {"title": "Domicilio", "fields": [{"name": "calle", "type": "text", "label": "Calle", "required": true}, {"name": "numero", "type": "text", "label": "N\u00famero", "required": true}, {"name": "piso", "type": "text", "label": "Piso", "required": false}, {"name": "depto", "type": "text", "label": "Departamento", "required": false}, {"name": "localidad", "type": "text", "label": "Localidad", "required": true}, {"name": "provincia", "type": "text", "label": "Provincia", "required": true}, {"name": "codigo_postal", "type": "text", "label": "C\u00f3digo postal", "required": true}]}, {"title": "Formaci\u00f3n profesional", "fields": [{"name": "titulo", "type": "text", "label": "T\u00edtulo obtenido", "required": true, "placeholder": "Ej: Contador P\u00fablico, Abogado, Curso de Administraci\u00f3n\u2026"}, {"name": "institucion_titulo", "type": "text", "label": "Instituci\u00f3n emisora del t\u00edtulo", "required": true}, {"name": "ano_egreso", "type": "number", "label": "A\u00f1o de egreso", "required": true, "validation": {"min": 1950, "max": 2050}}]}, {"title": "Documentaci\u00f3n requerida", "subtitle": "Sub\u00ed los archivos en PDF o JPG (m\u00e1x 10MB cada uno).", "fields": [{"name": "dni_frente", "type": "file", "label": "DNI - Frente", "accept": ["application/pdf", "image/jpeg", "image/png"], "required": true, "max_files": 1}, {"name": "dni_dorso", "type": "file", "label": "DNI - Dorso", "accept": ["application/pdf", "image/jpeg", "image/png"], "required": true, "max_files": 1}, {"name": "foto_carnet", "type": "file", "label": "Foto carnet 4x4", "accept": ["image/jpeg", "image/png"], "required": true, "max_files": 1, "hint": "Foto color reciente, fondo blanco, sin lentes ni gorro."}, {"name": "titulo_secundario_o_superior", "type": "file", "label": "T\u00edtulo emitido por entidad habilitada por el RPAC", "accept": ["application/pdf", "image/jpeg", "image/png"], "required": true, "max_files": 1, "hint": "Adjunt\u00e1 el t\u00edtulo o certificado emitido por una entidad habilitada por el Registro."}, {"name": "certificado_curso_administradores", "type": "file", "label": "Certificado del curso de administradores", "accept": ["application/pdf"], "required": true, "max_files": 1, "hint": "Aprobaci\u00f3n del curso integral de Administradores de Consorcios."}, {"name": "constancia_inscripcion_arca", "type": "file", "label": "Constancia de inscripci\u00f3n ARCA", "accept": ["application/pdf"], "required": true, "max_files": 1, "hint": "Debe tener declarado el C\u00f3digo de Actividad 682010."}, {"name": "constancia_arba_iibb", "type": "file", "label": "Constancia de ARBA Ingresos Brutos", "accept": ["application/pdf"], "required": true, "max_files": 1, "hint": "Debe tener declarado el C\u00f3digo de Actividad 682010."}, {"name": "cv", "type": "file", "label": "Curr\u00edculum Vitae (opcional)", "accept": ["application/pdf"], "required": false, "max_files": 1}]}, {"title": "Listado de consorcios (si ya est\u00e1s administrando)", "subtitle": "Opcional. Si ya administr\u00e1s consorcios, descarg\u00e1 la planilla modelo, completala y subila.", "fields": [{"name": "planilla_consorcios_modelo", "type": "file_download", "label": "Descarg\u00e1 la planilla modelo", "required": false, "download_url": "https://kaoyhkebnidzqjixvchh.supabase.co/storage/v1/object/public/formulario-descargas/ddjj-anual/datos-de-consorcios-modelo.xlsx", "download_filename": "Datos de Consorcios - Gesti\u00f3n Global.xlsx", "hint": "Descargala, completala en tu computadora con los datos de los consorcios que administr\u00e1s y subila m\u00e1s abajo."}, {"name": "planilla_consorcios_completa", "type": "file", "label": "Listado de consorcios administrados (planilla completa)", "required": false, "hint": "Sub\u00ed la planilla modelo que descargaste arriba ya completa."}]}, {"title": "Costos del tr\u00e1mite", "fields": [{"name": "costos_matriculacion", "type": "costos_info", "label": "Costos del tr\u00e1mite", "hint": "Honorarios + Gastos del tr\u00e1mite (certificados y tasas).", "costos": {"items": [{"label": "Tr\u00e1mite de 15 d\u00edas h\u00e1biles", "precio": "$175.000,00", "nota": "Sujeto a modificaci\u00f3n seg\u00fan el valor de las tasas."}], "nota_total": "La transferencia debe ser por el total informado.", "cuenta": {"titular": "Mercado Pago", "cvu": "0000003100053534352305", "alias": "GestionGlobal.ar", "cuit_cuil": "27225982746"}}}, {"name": "comprobante_pago_matricula", "type": "file", "label": "Comprobante de pago de matr\u00edcula", "required": true, "hint": "Transferencia, Mercado Pago o dep\u00f3sito a nombre de Gesti\u00f3n Global. Si vas a usar un voucher 100% lo pod\u00e9s ingresar en la secci\u00f3n \"Voucher\" y este campo se omitir\u00e1 autom\u00e1ticamente."}]}, {"title": "Declaraci\u00f3n jurada", "fields": [{"name": "declaracion_jurada", "type": "checkbox", "label": "Declaro bajo juramento que los datos consignados son verdaderos", "required": true}]}], "post_submit": {"message": "Recibimos tu solicitud de matriculaci\u00f3n. Vamos a revisar la documentaci\u00f3n y nos contactamos por mail dentro de las 72 hs h\u00e1biles."}, "submit_label": "Iniciar tr\u00e1mite de matriculaci\u00f3n"}'::jsonb WHERE slug = 'matriculacion-rpac';

