UPDATE public.formularios SET schema = '{"sections": [{"title": "Datos del solicitante", "fields": [{"name": "apellido", "type": "text", "label": "Apellido", "required": true, "placeholder": "Garc\u00eda"}, {"name": "nombre", "type": "text", "label": "Nombre", "required": true, "placeholder": "Diego"}, {"name": "dni", "type": "text", "label": "DNI", "required": true, "hint": "Sin puntos ni guiones."}, {"name": "cuit", "type": "text", "label": "CUIT/CUIL", "required": true, "hint": "11 d\u00edgitos sin guiones."}, {"name": "clave_fiscal_arca", "type": "text", "label": "Clave Fiscal ARCA", "required": true, "hint": "Tu clave fiscal de ARCA (ex AFIP)."}, {"name": "email", "type": "email", "label": "Correo electr\u00f3nico", "required": true}, {"name": "celular", "type": "tel", "label": "Celular", "required": true, "hint": "Inclu\u00ed caracter\u00edstica con el 9 (m\u00f3vil).", "placeholder": "+54 11 5555-1234"}, {"name": "matricula", "type": "text", "label": "N\u00famero de matr\u00edcula RPAC", "required": true, "hint": "Tal como figura en tu credencial."}, {"name": "legajo_rpac", "type": "text", "label": "N\u00famero de legajo RPAC", "required": true, "hint": "El n\u00famero de legajo que te asign\u00f3 el Registro al matricularte."}]}, {"title": "Destino del certificado", "fields": [{"name": "destino_certificado", "type": "select", "label": "\u00bfA qui\u00e9n va dirigido el certificado?", "options": ["presentacion_a_organismo", "consorcio", "otra"], "required": true}, {"name": "cuit_consorcio", "type": "text", "label": "CUIT del consorcio", "required": true, "condition": {"field": "destino_certificado", "equals": "consorcio"}}, {"name": "denominacion_consorcio", "type": "text", "label": "Denominaci\u00f3n del consorcio", "required": true, "condition": {"field": "destino_certificado", "equals": "consorcio"}}]}, {"title": "Plazo de emisi\u00f3n", "fields": [{"name": "urgencia", "type": "radio", "label": "Plazo de emisi\u00f3n", "options": ["5_dias_habiles"], "requi