UPDATE public.formularios SET schema = '{"sections": [{"title": "Identificaci\u00f3n", "fields": [{"name": "apellido", "type": "text", "label": "Apellido", "required": true, "placeholder": "Garc\u00eda"}, {"name": "nombre", "type": "text", "label": "Nombre", "required": true, "placeholder": "Diego"}, {"name": "dni", "type": "text", "label": "DNI", "required": true, "hint": "Sin puntos ni guiones."}, {"name": "cuit", "type": "text", "label": "CUIT/CUIL", "required": true, "hint": "11 d\u00edgitos sin guiones."}, {"name": "email", "type": "email", "label": "Correo electr\u00f3nico", "required": true}, {"name": "celular", "type": "tel", "label": "Celular", "required": true, "hint": "Inclu\u00ed caracter\u00edstica con el 9 (m\u00f3vil).", "placeholder": "+54 11 5555-1234"}, {"name": "matricula_rpac", "type": "text", "label": "N\u00famero de matr\u00edcula RPAC", "required": true, "hint": "Tal como figura en tu credencial."}]}, {"title": "Per\u00edodo declarado", "fields": [{"name": "periodo", "type": "select", "label": "A\u00f1o fiscal", "options": ["2024", "2025"], "required": true, "hint": "El per\u00edodo 2026 estar\u00e1 habilitado cuando termine el a\u00f1o fiscal."}]}, {"title": "Documentaci\u00f3n requerida", "fields": [{"name": "planilla_consorcios_modelo", "type": "file_download", "label": "Descarg\u00e1 la planilla modelo", "required": false, "download_url": "https://kaoyhkebnidzqjixvchh.supabase.co/storage/v1/object/public/formulario-descargas/ddjj-anual/datos-de-consorcios-modelo.xlsx", "download_filename": "Datos de Consorcios - Gesti\u00f3n Global.xlsx", "hint": "Descargala, completala en tu computadora con los datos de los consorcios que administr\u00e1s durante el per\u00edodo y subila m\u00e1s abajo."}, {"name": "planilla_consorcios_completa", "type": "file", "label": "Listado de consorcios administrados (planilla completa)", "required": true, "hint": "Sub\u00ed la planilla modelo que descargaste arriba ya completa con los datos de los consorcios del per\u00edodo declarado."}]}, {"title": "Costos del tr\u00e1mite", "fields": [{"name": "costos_ddjj", "type": "costos_info", "label": "Costos del tr\u00e1mite", "hint": "Honorarios y tasas DDJJ Anual RPAC. Se liquidan luego de presentada la declaraci\u00f3n, seg\u00fan la cantidad de consorcios.", "costos": {"items": [{"label": "Hasta 5 consorcios", "precio": "$16.500,00", "nota": "por consorcio"}, {"label": "De 6 a 10 consorcios", "precio": "$16.000,00", "nota": "por consorcio"}, {"label": "De 11 a 15 consorcios", "precio": "$15.500,00", "nota": "por consorcio"}, {"label": "M\u00e1s de 15 consorcios", "precio": "$15.000,00", "nota": "por consorcio"}], "nota_total": "Los clientes de Gesti\u00f3n Global que realizaron alg\u00fan tr\u00e1mite con nosotros pagan $14.500,00 por consorcio, independientemente de la cantidad que tengan.", "cuenta": {"titular": "Mercado Pago", "cvu": "0000003100053534352305", "alias": "GestionGlobal.ar", "cuit_cuil": "27225982746"}, "nota_extra": "IMPORTANTE: en este formulario NO se adjunta comprobante de pago. La liquidaci\u00f3n se realiza luego de presentada la DDJJ seg\u00fan la cantidad de consorcios declarados; te confirmamos el monto exacto por mail."}}]}, {"title": "Declaraci\u00f3n jurada", "fields": [{"name": "declaracion_jurada", "type": "checkbox", "label": "Declaro bajo juramento que los datos consignados son verdaderos", "required": true}]}], "post_submit": {"message": "DDJJ recibida. Revisamos y te confirmamos la presentaci\u00f3n y el monto a abonar por mail."}, "submit_label": "Presentar DDJJ"}'::jsonb WHERE slug = 'ddjj-anual';

